/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across all channels
 * (email, SMS, webhook). Each channel has independent enabled/categories
 * settings. Email additionally supports delivery frequency (digest batching).
 *
 * History: Originally email-only (Session 3). Refactored to multi-channel
 * after SMS (Session 8) and webhook support were added.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * How often email notifications are delivered.
 * - immediate: sent as soon as the event occurs
 * - daily_digest: batched and sent once per day
 * - weekly_digest: batched and sent once per week
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Base per-channel notification settings shared by all channels.
 */
export interface ChannelPreferences {
  /** Global toggle — if false, no notifications are sent on this channel */
  enabled: boolean;
  /** Which notification categories the user wants to receive on this channel */
  categories: NotificationType[];
}

/**
 * Email-specific notification settings.
 * Extends base channel preferences with delivery frequency.
 */
export interface EmailPreferences extends ChannelPreferences {
  /** How often to deliver emails */
  frequency: EmailFrequency;
}

/**
 * SMS notification settings.
 */
export interface SmsPreferences extends ChannelPreferences {}

/**
 * Webhook notification settings.
 */
export interface WebhookPreferences extends ChannelPreferences {}

/**
 * Full user notification preferences.
 */
export interface UserPreferences {
  /** The user this preferences record belongs to */
  userId: string;
  /** Email channel settings */
  email: EmailPreferences;
  /** SMS channel settings */
  sms: SmsPreferences;
  /** Webhook channel settings */
  webhook: WebhookPreferences;
  /** When preferences were last updated */
  updatedAt: Date;
}

/**
 * Input for updating user notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdatePreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * All notification types that are enabled by default for new users.
 */
export const DEFAULT_EMAIL_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default SMS categories — same as email by default.
 */
export const DEFAULT_SMS_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Default webhook categories — same as email by default.
 */
export const DEFAULT_WEBHOOK_CATEGORIES: NotificationType[] = [
  'order_confirmation',
  'order_status_update',
  'welcome',
  'account_updated',
];

/**
 * Maps a NotificationChannel to the corresponding key in UserPreferences.
 */
export function channelToPreferencesKey(channel: NotificationChannel): 'email' | 'sms' | 'webhook' | null {
  switch (channel) {
    case 'email': return 'email';
    case 'sms': return 'sms';
    case 'webhook': return 'webhook';
    default: return null;
  }
}

/**
 * Create default preferences for a new user.
 * All channels are enabled by default with all categories.
 */
export function createDefaultPreferences(userId: string): UserPreferences {
  return {
    userId,
    email: {
      enabled: true,
      categories: [...DEFAULT_EMAIL_CATEGORIES],
      frequency: 'immediate',
    },
    sms: {
      enabled: true,
      categories: [...DEFAULT_SMS_CATEGORIES],
    },
    webhook: {
      enabled: true,
      categories: [...DEFAULT_WEBHOOK_CATEGORIES],
    },
    updatedAt: new Date(),
  };
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user notification preferences and
 * a shouldSend() method that the NotificationService uses to check
 * whether a notification should be delivered to a given user on any channel.
 *
 * Storage: In-memory Map keyed by userId. Default preferences are
 * created on first access (lazy initialization).
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { EmailFrequency, UpdatePreferencesInput, UserPreferences } from '../models/user-preferences.js';
import { channelToPreferencesKey, createDefaultPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

/**
 * Deep-copy a UserPreferences object to prevent external mutation.
 */
function clonePreferences(prefs: UserPreferences): UserPreferences {
  return {
    ...prefs,
    email: { ...prefs.email, categories: [...prefs.email.categories] },
    sms: { ...prefs.sms, categories: [...prefs.sms.categories] },
    webhook: { ...prefs.webhook, categories: [...prefs.webhook.categories] },
  };
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');
  private preferences: Map<string, UserPreferences> = new Map();

  /**
   * Get preferences for a user. If none exist, creates and stores defaults.
   */
  getPreferences(userId: string): UserPreferences {
    let prefs = this.preferences.get(userId);
    if (!prefs) {
      this.logger.info(`Creating default preferences for user ${userId}`);
      prefs = createDefaultPreferences(userId);
      this.preferences.set(userId, prefs);
    }
    return clonePreferences(prefs);
  }

  /**
   * Update preferences for a user. Merges provided fields with existing preferences.
   */
  updatePreferences(userId: string, input: UpdatePreferencesInput): UserPreferences {
    const current = this.getPreferences(userId);

    if (input.email) {
      if (input.email.enabled !== undefined) {
        current.email.enabled = input.email.enabled;
      }
      if (input.email.categories !== undefined) {
        current.email.categories = [...input.email.categories];
      }
      if (input.email.frequency !== undefined) {
        current.email.frequency = input.email.frequency;
      }
    }

    if (input.sms) {
      if (input.sms.enabled !== undefined) {
        current.sms.enabled = input.sms.enabled;
      }
      if (input.sms.categories !== undefined) {
        current.sms.categories = [...input.sms.categories];
      }
    }

    if (input.webhook) {
      if (input.webhook.enabled !== undefined) {
        current.webhook.enabled = input.webhook.enabled;
      }
      if (input.webhook.categories !== undefined) {
        current.webhook.categories = [...input.webhook.categories];
      }
    }

    current.updatedAt = new Date();
    this.preferences.set(userId, current);

    this.logger.info(`Updated preferences for user ${userId}`);
    return clonePreferences(current);
  }

  /**
   * Check whether a notification should be sent to a user on any channel.
   *
   * Returns false if:
   * - The channel has no preferences mapping (e.g., in_app)
   * - The channel is globally disabled for the user
   * - The notification type is not in the user's subscribed categories for that channel
   */
  shouldSend(userId: string, channel: NotificationChannel, notificationType: NotificationType): boolean {
    const key = channelToPreferencesKey(channel);
    if (!key) {
      this.logger.info(`No preferences mapping for channel ${channel}, allowing send`);
      return true;
    }

    const prefs = this.getPreferences(userId);
    const channelPrefs = prefs[key];

    if (!channelPrefs.enabled) {
      this.logger.info(`${channel} disabled for user ${userId}, suppressing ${notificationType}`);
      return false;
    }

    if (!channelPrefs.categories.includes(notificationType)) {
      this.logger.info(`User ${userId} not subscribed to ${notificationType} on ${channel}, suppressing`);
      return false;
    }

    return true;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   * Backward-compatible convenience method — delegates to shouldSend().
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    return this.shouldSend(userId, 'email', notificationType);
  }

  /**
   * Get the email frequency setting for a user.
   */
  getEmailFrequency(userId: string): EmailFrequency {
    return this.getPreferences(userId).email.frequency;
  }

  /**
   * Delete preferences for a user (e.g., on account deletion).
   */
  deletePreferences(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  /**
   * Clear all stored preferences (useful for testing).
   */
  clear(): void {
    this.preferences.clear();
  }
}

