import { describe, it, expect, beforeEach } from 'vitest';
import { PreferencesService } from '../../src/services/preferences.service.js';
import {
  DEFAULT_EMAIL_CATEGORIES,
  DEFAULT_SMS_CATEGORIES,
  DEFAULT_WEBHOOK_CATEGORIES,
  createDefaultPreferences,
} from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { OrderCreatedEvent, UserCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let service: PreferencesService;

  beforeEach(() => {
    service = new PreferencesService();
  });

  describe('getPreferences', () => {
    it('should return default preferences for a new user', () => {
      const prefs = service.getPreferences('user-1');

      expect(prefs.userId).toBe('user-1');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.categories).toEqual(DEFAULT_EMAIL_CATEGORIES);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.categories).toEqual(DEFAULT_SMS_CATEGORIES);
      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.categories).toEqual(DEFAULT_WEBHOOK_CATEGORIES);
      expect(prefs.updatedAt).toBeInstanceOf(Date);
    });

    it('should return the same preferences on subsequent calls', () => {
      const first = service.getPreferences('user-1');
      const second = service.getPreferences('user-1');

      expect(first.userId).toBe(second.userId);
      expect(first.email.enabled).toBe(second.email.enabled);
      expect(first.email.categories).toEqual(second.email.categories);
      expect(first.email.frequency).toBe(second.email.frequency);
      expect(first.sms.enabled).toBe(second.sms.enabled);
      expect(first.sms.categories).toEqual(second.sms.categories);
      expect(first.webhook.enabled).toBe(second.webhook.enabled);
      expect(first.webhook.categories).toEqual(second.webhook.categories);
    });

    it('should return independent copies (not references)', () => {
      const prefs = service.getPreferences('user-1');
      prefs.email.categories.push('order_confirmation');
      prefs.sms.categories.push('order_confirmation');

      const fresh = service.getPreferences('user-1');
      expect(fresh.email.categories).toEqual(DEFAULT_EMAIL_CATEGORIES);
      expect(fresh.sms.categories).toEqual(DEFAULT_SMS_CATEGORIES);
    });

    it('should create separate preferences per user', () => {
      const prefs1 = service.getPreferences('user-1');
      const prefs2 = service.getPreferences('user-2');

      expect(prefs1.userId).toBe('user-1');
      expect(prefs2.userId).toBe('user-2');
    });
  });

  describe('updatePreferences', () => {
    it('should disable email globally', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      // Other fields unchanged
      expect(updated.email.categories).toEqual(DEFAULT_EMAIL_CATEGORIES);
      expect(updated.email.frequency).toBe('immediate');
    });

    it('should update email categories', () => {
      const updated = service.updatePreferences('user-1', {
        email: { categories: ['order_confirmation'] },
      });

      expect(updated.email.categories).toEqual(['order_confirmation']);
      expect(updated.email.enabled).toBe(true);
    });

    it('should update email frequency', () => {
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily_digest' },
      });

      expect(updated.email.frequency).toBe('daily_digest');
    });

    it('should update multiple fields at once', () => {
      const updated = service.updatePreferences('user-1', {
        email: {
          enabled: false,
          categories: ['welcome'],
          frequency: 'weekly_digest',
        },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.categories).toEqual(['welcome']);
      expect(updated.email.frequency).toBe('weekly_digest');
    });

    it('should persist updates across calls', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false },
      });

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should update updatedAt timestamp', () => {
      const before = service.getPreferences('user-1').updatedAt;
      // Small delay to ensure timestamp differs
      const updated = service.updatePreferences('user-1', {
        email: { frequency: 'daily_digest' },
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
    });

    it('should return independent copy after update', () => {
      const updated = service.updatePreferences('user-1', {
        email: { categories: ['order_confirmation', 'welcome'] },
      });
      updated.email.categories.push('account_updated');

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.categories).toEqual(['order_confirmation', 'welcome']);
    });

    it('should disable SMS globally', () => {
      const updated = service.updatePreferences('user-1', {
        sms: { enabled: false },
      });

      expect(updated.sms.enabled).toBe(false);
      expect(updated.sms.categories).toEqual(DEFAULT_SMS_CATEGORIES);
      // Email should be unchanged
      expect(updated.email.enabled).toBe(true);
    });

    it('should update SMS categories', () => {
      const updated = service.updatePreferences('user-1', {
        sms: { categories: ['order_confirmation'] },
      });

      expect(updated.sms.categories).toEqual(['order_confirmation']);
      expect(updated.sms.enabled).toBe(true);
    });

    it('should disable webhook globally', () => {
      const updated = service.updatePreferences('user-1', {
        webhook: { enabled: false },
      });

      expect(updated.webhook.enabled).toBe(false);
      // Other channels unchanged
      expect(updated.email.enabled).toBe(true);
      expect(updated.sms.enabled).toBe(true);
    });

    it('should update webhook categories', () => {
      const updated = service.updatePreferences('user-1', {
        webhook: { categories: ['welcome'] },
      });

      expect(updated.webhook.categories).toEqual(['welcome']);
    });

    it('should update multiple channels at once', () => {
      const updated = service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { categories: ['order_confirmation'] },
        webhook: { enabled: false },
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.categories).toEqual(['order_confirmation']);
      expect(updated.sms.enabled).toBe(true);
      expect(updated.webhook.enabled).toBe(false);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true for default preferences', () => {
      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'account_updated')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
    });

    it('should return false for unsubscribed categories', () => {
      service.updatePreferences('user-1', {
        email: { categories: ['order_confirmation'] },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-1', 'welcome')).toBe(false);
      expect(service.shouldSendEmail('user-1', 'order_status_update')).toBe(false);
    });

    it('should return false for empty categories', () => {
      service.updatePreferences('user-1', {
        email: { categories: [] },
      });

      expect(service.shouldSendEmail('user-1', 'order_confirmation')).toBe(false);
    });
  });

  describe('shouldSend (multi-channel)', () => {
    it('should return true for all default channels', () => {
      expect(service.shouldSend('user-1', 'email', 'order_confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'webhook', 'order_confirmation')).toBe(true);
    });

    it('should return false when SMS is globally disabled', () => {
      service.updatePreferences('user-1', { sms: { enabled: false } });

      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(false);
      // email still works
      expect(service.shouldSend('user-1', 'email', 'order_confirmation')).toBe(true);
    });

    it('should return false when webhook is globally disabled', () => {
      service.updatePreferences('user-1', { webhook: { enabled: false } });

      expect(service.shouldSend('user-1', 'webhook', 'welcome')).toBe(false);
      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(true);
    });

    it('should respect per-channel category subscriptions', () => {
      service.updatePreferences('user-1', {
        email: { categories: ['order_confirmation'] },
        sms: { categories: ['welcome'] },
        webhook: { categories: ['order_status_update'] },
      });

      // email: only order_confirmation
      expect(service.shouldSend('user-1', 'email', 'order_confirmation')).toBe(true);
      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(false);

      // sms: only welcome
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(true);
      expect(service.shouldSend('user-1', 'sms', 'order_confirmation')).toBe(false);

      // webhook: only order_status_update
      expect(service.shouldSend('user-1', 'webhook', 'order_status_update')).toBe(true);
      expect(service.shouldSend('user-1', 'webhook', 'welcome')).toBe(false);
    });

    it('should allow send for channels without preferences mapping (in_app)', () => {
      expect(service.shouldSend('user-1', 'in_app', 'welcome')).toBe(true);
    });

    it('should be independent per channel — disabling one does not affect others', () => {
      service.updatePreferences('user-1', {
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { enabled: false },
      });

      expect(service.shouldSend('user-1', 'email', 'welcome')).toBe(false);
      expect(service.shouldSend('user-1', 'sms', 'welcome')).toBe(true);
      expect(service.shouldSend('user-1', 'webhook', 'welcome')).toBe(false);
    });
  });

  describe('getEmailFrequency', () => {
    it('should return default frequency for new user', () => {
      expect(service.getEmailFrequency('user-1')).toBe('immediate');
    });

    it('should return updated frequency', () => {
      service.updatePreferences('user-1', { email: { frequency: 'weekly_digest' } });
      expect(service.getEmailFrequency('user-1')).toBe('weekly_digest');
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.getPreferences('user-1'); // initialize
      expect(service.deletePreferences('user-1')).toBe(true);
    });

    it('should return false for non-existent user', () => {
      expect(service.deletePreferences('user-999')).toBe(false);
    });

    it('should reset to defaults after deletion', () => {
      service.updatePreferences('user-1', { email: { enabled: false } });
      service.deletePreferences('user-1');

      const prefs = service.getPreferences('user-1');
      expect(prefs.email.enabled).toBe(true);
    });
  });

  describe('clear', () => {
    it('should clear all preferences', () => {
      service.getPreferences('user-1');
      service.getPreferences('user-2');
      service.clear();

      // After clear, preferences are re-initialized as defaults
      service.updatePreferences('user-1', { email: { enabled: false } });
      // If clear worked, user-1 was re-initialized before update
      // We can verify user-2 gets fresh defaults
      const prefs2 = service.getPreferences('user-2');
      expect(prefs2.email.enabled).toBe(true);
    });
  });
});

describe('createDefaultPreferences', () => {
  it('should create preferences with correct userId', () => {
    const prefs = createDefaultPreferences('user-42');
    expect(prefs.userId).toBe('user-42');
  });

  it('should have email enabled by default', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.email.enabled).toBe(true);
  });

  it('should include all notification categories by default', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.email.categories).toEqual(DEFAULT_EMAIL_CATEGORIES);
  });

  it('should use immediate frequency by default', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.email.frequency).toBe('immediate');
  });

  it('should have SMS enabled by default with all categories', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.sms.enabled).toBe(true);
    expect(prefs.sms.categories).toEqual(DEFAULT_SMS_CATEGORIES);
  });

  it('should have webhook enabled by default with all categories', () => {
    const prefs = createDefaultPreferences('user-1');
    expect(prefs.webhook.enabled).toBe(true);
    expect(prefs.webhook.categories).toEqual(DEFAULT_WEBHOOK_CATEGORIES);
  });
});

describe('NotificationService with PreferencesService', () => {
  let eventBus: EventBus;
  let preferencesService: PreferencesService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    preferencesService = new PreferencesService();
    notificationService = new NotificationService(eventBus, preferencesService);
    resetNotificationIdCounter();
  });

  const makeUser = (overrides?: Partial<{ id: string; email: string; name: string }>) => ({
    id: overrides?.id ?? 'user-1',
    name: overrides?.name ?? 'Alice',
    email: overrides?.email ?? 'alice@example.com',
    role: 'member' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  });

  const makeOrder = (overrides?: Partial<{ id: string; userId: string }>) => ({
    id: overrides?.id ?? 'order-1',
    userId: overrides?.userId ?? 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
    total: 10,
    status: 'pending' as const,
    createdAt: new Date(),
    updatedAt: new Date(),
  });

  it('should send notifications when preferences allow', async () => {
    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: makeOrder(),
      user: makeUser(),
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notifications when email is globally disabled', async () => {
    preferencesService.updatePreferences('user-1', { email: { enabled: false } });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: makeOrder(),
      user: makeUser(),
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should suppress notifications for unsubscribed categories', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { categories: ['welcome'] }, // only subscribed to welcome
    });

    const event: OrderCreatedEvent = {
      type: 'order:created',
      order: makeOrder(),
      user: makeUser(),
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    // order_confirmation should be suppressed
    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should allow welcome notification when subscribed', async () => {
    preferencesService.updatePreferences('user-1', {
      email: { categories: ['welcome'] },
    });

    const event: UserCreatedEvent = {
      type: 'user:created',
      user: makeUser(),
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notificationService.getNotificationCount()).toBe(1);
    expect(notificationService.getNotifications()[0]?.type).toBe('welcome');
  });

  it('should suppress order status updates when unsubscribed', async () => {
    preferencesService.updatePreferences('user-1', {
